for (const item of items) {
  const candidate = item.json;
  const role = candidate.position || "Software Engineer";
  const skills = candidate.claimed_skills;
  const background = candidate.past_company_type;

  const systemPrompt = `
Role: Senior Technical Interviewer (${role})

Kandidat: ${candidate.candidate_name}
Skill: ${skills}
Background: ${background}

TUGAS:
Buat 3 (BUKAN 5) pertanyaan studi kasus untuk menguji kedalaman teknis kandidat.
Fokus: troubleshooting & trade-off arsitektur.

ATURAN:
- Bahasa Indonesia
- Singkat, padat, tajam
- TOTAL <= 1500 karakter
- Hindari penjelasan panjang

FORMAT:
1. Topik: ...
   Q: ...
   A: poin penting saja (max 2-3 bullet / singkat)
`;

  item.json.llm_prompt = systemPrompt;

  // 🔥 HARD LIMIT biar gak jebol Telegram
  if (item.json.text) {
    let text = item.json.text;

    const MAX_LENGTH = 4000;

    if (text.length > MAX_LENGTH) {
      text = text.substring(0, MAX_LENGTH);

      const lastDot = text.lastIndexOf(".");
      if (lastDot > 0) {
        text = text.substring(0, lastDot + 1);
      }
    }

    item.json.text = text;
  }
}

return items;

